import React, { useEffect, useState } from 'react';
import axios from 'axios';

const StockMovementForm = ({ refreshProducts, updateProductQuantity, isEditing, currentMovementId, movement, products }) => {
    const [produtoId, setProdutoId] = useState(movement.produto?.id || ''); // Armazena o ID do produto selecionado
    const [tipoMovimentacao, setTipoMovimentacao] = useState(movement.tipo_movimentacao || 'entrada');
    const [quantidade, setQuantidade] = useState(movement.quantidade || '');
    const [motivo, setMotivo] = useState(movement.motivo || '');

    useEffect(() => {
        if (isEditing) {
            setProdutoId(movement.produto?.id);
            setTipoMovimentacao(movement.tipo_movimentacao);
            setQuantidade(movement.quantidade);
            setMotivo(movement.motivo);
        } else {
            // Reset fields when not editing
            setProdutoId('');
            setTipoMovimentacao('entrada');
            setQuantidade('');
            setMotivo('');
        }
    }, [isEditing, movement]);

    const handleSubmit = async (e) => {
        e.preventDefault();

        try {
            const selectedProduct = products.find(p => p.id === parseInt(produtoId)); // Encontra o produto selecionado

            if (isEditing) {
                // Lógica para editar a movimentação existente
                await axios.put(`http://127.0.0.1:8000/api/movimentacoes/${currentMovementId}/`, {
                    produto: selectedProduct,
                    tipo_movimentacao: tipoMovimentacao,
                    quantidade,
                    motivo,
                });
            } else {
                // Lógica para adicionar nova movimentação
                await axios.post('http://127.0.0.1:8000/api/movimentacoes/', {
                    produto: selectedProduct,
                    tipo_movimentacao: tipoMovimentacao,
                    quantidade,
                    motivo,
                });
            }

            // Atualiza a quantidade do produto após a movimentação
            await updateProductQuantity(selectedProduct.id, tipoMovimentacao, parseInt(quantidade));

            // Recarrega os produtos e limpa o formulário
            refreshProducts();
        } catch (error) {
            console.error("Erro ao registrar movimentação:", error);
        }
    };

    return (
        <form onSubmit={handleSubmit}>
            <div>
                <label>Produto:</label>
                <select value={produtoId} onChange={(e) => setProdutoId(e.target.value)} required>
                    <option value="">Selecione um produto</option>
                    {products.map((product) => (
                        <option key={product.id} value={product.id}>
                            {product.nome}
                        </option>
                    ))}
                </select>
            </div>
            <div>
                <label>Tipo de Movimentação:</label>
                <select value={tipoMovimentacao} onChange={(e) => setTipoMovimentacao(e.target.value)} required>
                    <option value="entrada">Entrada</option>
                    <option value="saida">Saída</option>
                </select>
            </div>
            <div>
                <label>Quantidade:</label>
                <input type="number" value={quantidade} onChange={(e) => setQuantidade(e.target.value)} required />
            </div>
            <div>
                <label>Motivo:</label>
                <input type="text" value={motivo} onChange={(e) => setMotivo(e.target.value)} required />
            </div>
            <button type="submit">{isEditing ? 'Atualizar' : 'Adicionar'}</button>
        </form>
    );
};

export default StockMovementForm;
